- 'fan turnout' refers to the attendance at games; 
- 'average scores' refers to the average runs scored by a team.

sql:
SELECT player_name, at_bats, hits
FROM player_stats
WHERE player_id = 1;

SELECT dp_count
FROM double_plays
WHERE team_id = '1' AND game_id = 1;

SELECT SUM(dp_count) AS total_double_plays
FROM double_plays
WHERE team_id = '0' AND game_id = 1;

